mapper.select:
SELECT s.biz_no AS bizNo, s.style_name AS styleName, s.description AS description, s.prompt_summary AS promptSummary, s.prompt AS prompt, s.scope AS scope, s.publisher_user_id AS publisherUserId, u.nickname AS publisherName, s.price AS price, s.total_uses AS totalUses, s.weekly_uses AS weeklyUses, s.weekly_earnings AS weeklyEarnings, s.milestone_bonus AS milestoneBonus, s.enable_status AS enableStatus, s.created_at AS createdAt FROM u_style_market s LEFT JOIN u_user u ON u.id = s.publisher_user_id AND u.is_deleted = 0 WHERE s.is_deleted = 0 AND s.enable_status = #{enableStatus}
AND (s.style_name LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY s.id DESC LIMIT #{offset}, #{limit}
